// 1. Capture the raw input from the AI Tool call
const input = $input.first().json;

// 2. Parse the string if it arrives as 'query' or 'arguments' string
let data;
try {
  // AI Agents often wrap tool arguments in a string called "query" or "arguments"
  const rawString = input.query || input.arguments || JSON.stringify(input);
  data = typeof rawString === 'string' ? JSON.parse(rawString) : rawString;
} catch (e) {
  // Fallback if the data is already parsed or in a different format
  data = input;
}

// 3. Extract exactly two variables
return {
  doctor_id: data.doctor_id || "MISSING_ID",
  start_date_time: data.start_date_time || "MISSING_TIME"
};

return {
  result: `Good news! All slots are available for this day.`
};

// 1. Define your full working day slots
const allSlots = ["09:00", "10:00", "11:00", "12:00", "14:00", "15:00", "16:00", "17:00", "18:00"];

// 2. Get the booked times from the Postgres results
// We extract just the "HH:mm" part from the ISO string
const bookedTimes = $input.all().map(item => {
  const date = new Date(item.json.start_time);
  return date.getUTCHours().toString().padStart(2, '0') + ":" + 
         date.getUTCMinutes().toString().padStart(2, '0');
});

// 3. Filter the full list to find what's actually free
const freeSlots = allSlots.filter(slot => !bookedTimes.includes(slot));

return { status: "partially_booked", free_slots: freeSlots, booked_slots: bookedTimes };
